+		u.Out().Printf("text\t%s", ann.Text)
+	}
+	if ann.ScheduledTime != "" {
+		u.Out().Printf("scheduled\t%s", ann.ScheduledTime)
+	}
+	if ann.AlternateLink != "" {
+		u.Out().Printf("link\t%s", ann.AlternateLink)
+	}
+	return nil
+}
