+
+	if outfmt.IsJSON(ctx) {
+		return outfmt.WriteJSON(os.Stdout, map[string]any{
+			"ok":           true,
+			"courseId":     courseID,
+			"courseworkId": courseworkID,
+			"submissionId": submissionID,
+			"action":       action,
+		})
+	}
